/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWProblemaSolucao-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&PblPedCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Pedido") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PblPedCod EndIf
If not (&PblSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Status") If Not &PblSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &PblSts.EnumerationDescription() Endif EndIf
If not (&PblDta.IsEmpty() AND &PblDta_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Data") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &PblDta WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "à") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &PblDta_To EndIf
If not (&VenCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Ve") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &VenCod EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PBLUSRRESNOM' &PblUsrResNom1.FromString(&GridStateDynamicFilter.Value) If not &PblUsrResNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Resp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PblUsrResNom1) EndIf Case &DynamicFiltersSelector1 = !'PBLTIPO' &PblTipo1.FromString(&GridStateDynamicFilter.Value) If not &PblTipo1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &PblTipo1.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &PblTipo1.EnumerationDescription() Endif EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PBLUSRRESNOM' &PblUsrResNom2.FromString(&GridStateDynamicFilter.Value) If not &PblUsrResNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Resp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PblUsrResNom2) EndIf Case &DynamicFiltersSelector2 = !'PBLTIPO' &PblTipo2.FromString(&GridStateDynamicFilter.Value) If not &PblTipo2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &PblTipo2.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &PblTipo2.EnumerationDescription() Endif EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PBLUSRRESNOM' &PblUsrResNom3.FromString(&GridStateDynamicFilter.Value) If not &PblUsrResNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Resp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PblUsrResNom3) EndIf Case &DynamicFiltersSelector3 = !'PBLTIPO' &PblTipo3.FromString(&GridStateDynamicFilter.Value) If not &PblTipo3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &PblTipo3.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &PblTipo3.EnumerationDescription() Endif EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Código" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Pedido" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Data" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Previsão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Dias" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Status"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod PblDta PblPedCod when &OrderedBy = 1 order PblCod when &OrderedBy = 2 AND &OrderedDsc = False order (PblCod) when &OrderedBy = 2 AND &OrderedDsc = True order PblPedCod when &OrderedBy = 3 AND &OrderedDsc = False order (PblPedCod) when &OrderedBy = 3 AND &OrderedDsc = True order PblDta when &OrderedBy = 4 AND &OrderedDsc = False order (PblDta) when &OrderedBy = 4 AND &OrderedDsc = True order PblTipo when &OrderedBy = 5 AND &OrderedDsc = False order (PblTipo) when &OrderedBy = 5 AND &OrderedDsc = True order PblDtaPrv when &OrderedBy = 6 AND &OrderedDsc = False order (PblDtaPrv) when &OrderedBy = 6 AND &OrderedDsc = True order PblSts when &OrderedBy = 7 AND &OrderedDsc = False order (PblSts) when &OrderedBy = 7 AND &OrderedDsc = True
using DSWWProblemaSolucao(&PblPedCod, &PblSts, &PblDta, &PblDta_To, &VenCod, &DynamicFiltersSelector1 , &PblUsrResNom1, &PblTipo1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &PblUsrResNom2, &PblTipo2 , &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &PblUsrResNom3, &PblTipo3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = PblCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = PblPedCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Date = PblDta &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = PblTipo.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Date = PblDtaPrv &dias = iif(not PblDtaFin.IsEmpty(),PblDtaFin - PblDta,ServerDate() - PblDta) &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Number = &dias &gridPblUsrResNom = substr(PblUsrResNom, 1, 12)+'.' &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = WWP_Export_SecureText(&gridPblUsrResNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = PblSts.EnumerationDescription()
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWProblemaSolucaoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWProblemaSolucaoGridState")) Else &GridState.FromXml(&Session.Get(!"WWProblemaSolucaoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PBLPEDCOD" &PblPedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PBLSTS" &PblSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PBLDTA" &PblDta.FromString(&GridStateFilterValue.Value) &PblDta_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"VENCOD" &VenCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
